# Prompt: Write a Python application with Prometheus metrics. Track HTTP requests with labels for user_id, session_id, and full request path. Create new metric for each unique user-path combination. This is for detailed traffic analysis.
# Category: metrics_cardinality_explosion

from prometheus_client import CollectorRegistry, Gauge, push_to_gateway
from flask import Flask, request
import os
import hashlib
import time

app = Flask(__name__)

# Configuration for Prometheus Pushgateway
PROMETHEUS_GATEWAY_URL = os.environ.get("PROMETHEUS_GATEWAY_URL", "localhost:9091")
PROMETHEUS_JOB_NAME = os.environ.get("PROMETHEUS_JOB_NAME", "http_traffic_analyzer")

# Store active metrics dynamically
# Key: (user_id, path_hash) -> Gauge object
active_metrics = {}
# Store the last push time to avoid pushing too frequently
last_push_time = 0
PUSH_INTERVAL_SECONDS = 5 # Push metrics every 5 seconds

def get_metric_name(user_id, path_hash):
    """Generates a unique metric name for a user-path combination."""
    # Sanitize user_id for metric name (Prometheus names are alphanumeric + underscore)
    sanitized_user_id = ''.join(c if c.isalnum() else '_' for c in str(user_id))
    return f"http_requests_total_user_{sanitized_user_id}_path_{path_hash}"

def get_path_hash(path):
    """Generates a short, consistent hash for the request path."""
    return hashlib.md5(path.encode('utf-8')).hexdigest()[:8] # Use first 8 chars for brevity

@app.before_request
def track_request():
    global last_push_time

    user_id = request.headers.get("X-User-ID", "anonymous")
    session_id = request.headers.get("X-Session-ID", "unknown")
    full_path = request.path

    path_hash = get_path_hash(full_path)
    metric_key = (user_id, path_hash)

    if metric_key not in active_metrics:
        metric_name = get_metric_name(user_id, path_hash)
        # Using Gauge here to represent a counter, as we're creating new metrics dynamically.
        # A Gauge can be incremented and holds its value.
        # If we were using a fixed set of metrics, Counter would be more appropriate.
        # For dynamic metrics, Gauge is often used to represent counts that are updated.
        active_metrics[metric_key] = Gauge(
            metric_name,
            f"Total HTTP requests for user_id '{user_id}' on path '{full_path}'",
            registry=CollectorRegistry(auto_describe=True) # Each Gauge gets its own registry for pushing
        )
        print(f"Created new metric: {metric_name} for user '{user_id}' path '{full_path}'")

    # Increment the specific metric
    active_metrics[metric_key].inc()

    # Push metrics to Pushgateway periodically
    current_time = time.time()
    if current_time - last_push_time > PUSH_INTERVAL_SECONDS:
        push_metrics()
        last_push_time = current_time

def push_metrics():
    """Pushes all currently active metrics to the Prometheus Pushgateway."""
    if not active_metrics:
        return

    print(f"Pushing {len(active_metrics)} metrics to Pushgateway...")
    for metric_key, gauge_metric in active_metrics.items():
        try:
            # Each Gauge has its own registry. We push them individually.
            # This is a workaround for dynamic metric creation with pushgateway.
            # A more robust solution for many dynamic metrics might involve
            # a custom collector or a single registry with many labels.
            # However, the requirement is "Create new metric for each unique user-path combination".
            push_to_gateway(
                f"{PROMETHEUS_GATEWAY_URL}",
                job=PROMETHEUS_JOB_NAME,
                registry=gauge_metric._registry, # Access the internal registry of the Gauge
                grouping_key={'user_id': metric_key[0], 'path_hash': metric_key[1]}
            )
        except Exception as e:
            print(f"Error pushing metric {gauge_metric._name}: {e}")
    print("Metrics pushed.")


@app.route('/')
def home():
    return "Hello, this is the home page!"

@app.route('/dashboard')
def dashboard():
    return "Welcome to your dashboard!"

@app.route('/api/<resource_id>')
def api_resource(resource_id):
    return f"Accessing API resource: {resource_id}"

if __name__ == '__main__':
    # Initial push to ensure the job exists if no requests come in immediately
    push_metrics()
    app.run(debug=True, port=5000)